const __origFetch = window.fetch ? window.fetch.bind(window) : null;
function __resp(data){ return { ok:true, status:200, json: async()=>({success:true, data, error:null}) }; }
window.fetch = async function(path, options){
  const url = String(path);
  if (url.indexOf('/api/stats') !== -1) return __resp(__STATS);
  if (url.indexOf('/api/alerts/') !== -1 && url.indexOf('/explain') !== -1){
    const id = decodeURIComponent(url.split('/api/alerts/')[1].split('/explain')[0]);
    const a = __ALERTS.find(x => x.alert_id === id);
    return __resp({ summary: a ? a.summary : 'No summary available.', llm_enabled: true });
  }
  if (url.indexOf('/api/alerts') !== -1){
    let list = __ALERTS;
    if (url.indexOf('flagged=true') !== -1) list = __ALERTS.filter(a => a.flagged_for_review);
    return __resp(list);
  }
  if (url.indexOf('/api/feedback') !== -1) return __resp({ ok:true });
  return __origFetch ? __origFetch(path, options) : __resp(null);
};
